var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"PHOTO_EXTRA_NULL_A","text":{"KOREA":"돌아왔다! 샤레이드의 챔피언들이 돌아왔어!","JPN":"戻ってきた！　シャレードのチャンピオンたちが戻ってきたぞ！","ENG":"They're back! Charade's champions have returned!","TWN":"她們回來了！查雷德的冠軍們回來了！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD"},{"id":"L4_1","type":"dialog","speaker":"PHOTO_EXTRA_NULL_B","text":{"KOREA":"코핀 컴퍼니의 펜릴 소대에게 시민들을 대표해 감사의 말씀을 전해드리고 싶은데요! 잠시 인터뷰에 응해 주실 수 있을까요?!","JPN":"コフィンカンパニーのフェンリル小隊に市民を代表し感謝の言葉を伝えたいのですが！　ちょっとだけインタビューに応じて頂けますか！？","ENG":"Excuse me! On behalf of all the citizens. I'd like to express our gratitude for Coffin Company's Fenrir Squad! Also, would you mind doing a small interview?!","TWN":"我想代表市民感謝科芬公司的芬里爾小隊，請問你們是否願意接受一次簡短的採訪？！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L5_1","type":"dialog","speaker":"PHOTO_EXTRA_NULL_C","text":{"KOREA":"그로니아의 무공수훈자인 크리스티나 브레히트 양과 호흡을 맞춰 싸우던데 두 분과는 어떤 관계이십니까?","JPN":"グロニアの受勲者であるクリスティーナ・ブレヒトさんとともに戦っていましたけど、二人はどのような関係ですか？","ENG":"We saw you fighting alongside Christina Brecht, Gronia's war hero who received the Medal of Honor.  May I ask what your relationship is with her?","TWN":"我們看到你一直與格羅尼亞的授勳者克莉絲蒂娜·布萊希特並肩作戰，請問你們是什麼關係？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PHOTO_EXTRA_NULL_D","text":{"KOREA":"그녀가 현재 본국에서 지명수배되고 있다는 사실은 알고 계신가요?! 지금 어디에 있죠?!","JPN":"彼女が現在本国では指名手配されていることは知っていますか！？　今はどこにいるんですか！？","ENG":"Did you know that she is currently a wanted criminal in her own country?! Where is she now?!","TWN":"你知道她目前已被本國通緝的事實嗎？她現在在哪裡？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"자, 자, 응급환자입니다. 다 죽어가는 영웅 앞길 막지 말고 옆으로 비켜주세요.","JPN":"さぁ、さぁ、救急患者ですよ。死にかけている英雄の前をふさがないで横にどいてくださいね。","ENG":"Hey, emergency patient comin' through. Step aside if you don't want the hero to die.","TWN":"好了，好了，這位是急救患者，我們的英雄需要治療，請讓一下。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"이 천장… 이젠 낯설지가 않네.","JPN":"この天井……もう見飽きたな。","ENG":"This ceiling... It's so familiar now.","TWN":"這個天花板……不再那麼陌生了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"선배님! 제가 밥 가져왔어요!","JPN":"先輩！　ご飯を持ってきました！","ENG":"Mina! I brought you your food!","TWN":"前輩，我給你帶了些吃的！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"노엘?","JPN":"ノエル？","ENG":"Noelle?","TWN":"洛艾兒？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"왜 네가 그걸 가져와? 너 다리에 깁스하고 있잖아. 의사가 특히 꼬리뼈를 조심하라던데.","JPN":"何であなたがそんなことするの？　脚にギプスをつけているのに。医者が特に尾骨には気を付けろって言ったよね。","ENG":"Why are you bringing that? You have a cast on your leg. Didn't the doctor tell you to be especially careful about your tailbone?","TWN":"為什麼是你給我帶來？你腿上打著石膏，而且醫生說要特別小心你的尾椎。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"괜찮아요. 선배님이 싸인 해 주신 덕분에 금방 나았…","JPN":"大丈夫です。先輩がしてくれたサインのおかげですぐ治っ……","ENG":"It's all right. You signed my cast, so I'll be good in no ti–","TWN":"沒關係，多虧了你的親筆簽名，我很快就好……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"꺄앗!!","JPN":"きゃあっ！！","ENG":"Kyaah!","TWN":"呀啊！！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_COMIC_03"},{"id":"L20_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"흐아앙, 괜찮으세요?","JPN":"ふええん、大丈夫ですか？","ENG":"Waah... Are you okay?","TWN":"嗚嗚，你還好嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…정수리가 국 때문에 뜨거워.","JPN":"……頭が汁のせいで熱い。","ENG":"...You poured hot soup all over my head.","TWN":"……湯灑在我頭上了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"수, 수건 금방 가져올게요!","JPN":"タ、タオルを取ってきます！","ENG":"I-I'll be right back with some towels!","TWN":"我，我馬上去拿毛巾！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…다른 병실에도 다녀온 거지? 두 사람은 상태가 어때 보였어?","JPN":"……他の病室にも行ってきたんだね？　二人はどうだった？","ENG":"...You visited the others too, right? How are the other two doing?","TWN":"……你去過別的病房嗎？她們怎麼樣了？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"두 분은 링거 맞으면서 엄청 신기한 자세로 주무시고 계시더라구요.","JPN":"お二人は点滴を打ちながらすごく変わった体勢で寝てましたよ。","ENG":"Both are sleeping in weird positions while getting an IV.","TWN":"她們打著點滴，正以非常神奇的姿勢睡覺。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"간호사분한테 들었는데, 사람이 너무 피곤할 땐 이틀을 넘게 잘 수도 있대요.","JPN":"看護師さんに聞きましたけど、人間って疲れすぎていると丸二日以上寝ることもあるらしいですよ。","ENG":"The nurse told me that people who are exhausted can sleep for over two days straight.","TWN":"我聽護士說，如果人筋疲力盡可以睡兩天兩夜呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"다행이네. 크게 다치지는 않은 것 같아서.","JPN":"よかったね。大きい怪我はないようで。","ENG":"That's good. I'm glad their injuries are minor.","TWN":"謝天謝地。看來傷勢不算太嚴重。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"거기 깍두기 좀 줄래? 오늘따라 젓가락질이 힘드네.","JPN":"そこの漬物取ってくれる？　今日はやけに箸を動かすのがきついね。","ENG":"Could you pass the radish kimchi? It's hard for me to use chopsticks right now.","TWN":"能給我夾一塊蘿蔔嗎？今天用筷子怎麼這麼費力。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네!","JPN":"はいっ！","ENG":"Okay!","TWN":"是！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아앙~ 하세요, 선배님!","JPN":"あ～んしてください、先輩！","ENG":"Say, \\"Ah,\\" Mina!","TWN":"張開嘴，前輩！啊～"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…아니다. 그냥 내가 먹을게.","JPN":"……いい。自分で食べる。","ENG":"...Never mind. I'll just eat it myself.","TWN":"……算了，還是我自己吃吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아! 오전에 힐데 대장님이 회사로 돌아오셨다면서요?","JPN":"あ！　午前にヒルデ隊長が会社に戻られたんですよね？","ENG":"Oh! I heard Commander Hilde came back to the company this morning!","TWN":"啊！我聽說希爾德隊長今早回公司了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"응. 잠깐 우리 괜찮냐고 물어보더니 그대로 다시 떠났대.","JPN":"うん。大丈夫かって聞いただけですぐまた出たんだってさ。","ENG":"Yeah. She asked if we were all right then left again.","TWN":"是的，她詢問了一下我們的傷勢，然後又馬上離開了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"김하나 부장님 말로는 소대장이랑 키가 비슷한 꼬맹이가 하나 더 있었다는데…","JPN":"ナカシマ部長の話によると、チビ小隊長ぐらいの大きさのおこちゃまがもう一人いたようだけど……","ENG":"Manager Kim said that there was another kid around the same height as the commander with her...","TWN":"據金荷娜部長說，還有一個和小隊長差不多高的小鬼……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"얼룩무늬꼬리가 엄청 부드러웠다나 뭐라나.","JPN":"しま模様の尻尾がとても柔らかかったとか何とか。","ENG":"She also said something about her striped tail being really soft and fluffy.","TWN":"還說什麼斑紋的尾巴特別柔軟。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"꼬리요? 그런 게 달려있는 사람도 있나요?","JPN":"尻尾ですか？　そんなものが付いている人もいるんですか？","ENG":"Tail? There are people who have tails?","TWN":"尾巴？人類長著尾巴？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"뭐, 세상이 요지경인데 꼬리 하나쯤 달려있어도 이상할 건 없겠지.","JPN":"まぁ、こんな世の中だし、尻尾が付いている人がいるくらいおかしなことでもないよ。","ENG":"Well, with the world like this, there's nothing shocking about a person having a tail.","TWN":"如今這世道，就算人類長著尾巴也不足為奇了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"넌 괜찮아?","JPN":"あなたは大丈夫？","ENG":"Are you okay?","TWN":"你還好嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"…네?","JPN":"……はい？","ENG":"...Huh?","TWN":"……嗯？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"아니 그냥… 평소보다 분위기가 좀 주눅 든 것 같아 보여서.","JPN":"いや、なんとなく……いつもより少し元気がない気がして。","ENG":"No, it's just... You seem a little down.","TWN":"沒什麼，只是你看起來……有些無精打采。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"신경 쓰지 마.","JPN":"まぁ気にするな。","ENG":"Never mind.","TWN":"沒關係。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"선배님.","JPN":"先輩。","ENG":"Mina?","TWN":"前輩。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"응?","JPN":"あ？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저…","JPN":"あの……","ENG":"Um...","TWN":"那個……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"퇴원하고 나면 휴가 좀 다녀와도 될까요?","JPN":"退院したら休暇をとってもいいですか？","ENG":"Could I take some days off after I get discharged from the hospital?","TWN":"出院後，我可以休假嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"상관은 없지만… 어디로 가려고?","JPN":"いいけど……どこへ行くんだ？","ENG":"I don't see why not, but... where are you going?","TWN":"當然……但你要去哪裡？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"헤헤, 본가에 좀 다녀오려고요.","JPN":"へへ、実家に行ってみようと思うんです。","ENG":"He he, I was thinking of visiting home.","TWN":"嘿嘿，我要回一趟老家。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그동안 여러가지 일들을 겪었더니, 갑자기 부모님 얼굴이 보고 싶어졌어요.","JPN":"今まで色んなことがあったから、急に両親の顔が見たくなって。","ENG":"After going through a lot of stuff, I suddenly wanted to see my parents.","TWN":"這段時間經歷了太多事，突然想去見見父母。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그래, 그렇게 해. 부사장님한테 내가 말해 둘 테니까.","JPN":"ああ、いいよ。副社長には私が言っておく。","ENG":"Okay, sure. I'll tell the Vice President.","TWN":"好，就這麼辦，我會轉告副總。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"subtitle","speaker":null,"text":{"KOREA":"로터스, 아마니 밸리. 코핀 컴퍼니 임시 지부.","JPN":"ロータス、アマニーバレー。コフィンカンパニーの臨時支部。","ENG":"Lotus, Amani Valley. Temporary Coffin Company Branch.","TWN":"洛德斯，和平谷。科芬公司臨時分公司。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"코핀 컴퍼니의 새로운 전초 기지입니다. 마음에 드시나요?","JPN":"コフィンカンパニーの新しい前哨基地です。いかがでしょうか。","ENG":"This is the new outpost of Coffin Company. Does it suit your taste?","TWN":"這裡是科芬公司的新前哨基地。喜歡嗎？"},"stage":{"bg":"BASEMENT","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"먼지 냄새가 좀 나지만, 컨테이너 신세를 지고 있는 본사 사정보단 낫군.","JPN":"少し埃っぽいが、コンテナで生活している本社よりはましか。","ENG":"Smells a little dusty, but it's better than the current container state that HQ is in.","TWN":"雖然有些異味，但總比貨櫃來得好。"},"stage":{"bg":"BASEMENT","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"대부분의 비용은 코핀 함선을 위한 시설 대여에 쓰였으니까요.","JPN":"費用の大半はコフィン艦船のための施設を借りる用途として使いましたから。","ENG":"That's because most of the budget was used to rent a facility for our ship, Coffin.","TWN":"因為大部分資金用於租用科芬艦船的設施。"},"stage":{"bg":"BASEMENT","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"모래폭풍이 심할 땐 격납고에서 지내시는 편이 더 안전할 겁니다.","JPN":"砂嵐が激しい時は格納庫で過ごした方がより安全です。","ENG":"It will also be safer to stay in the hangar when sandstorms are severe.","TWN":"沙塵暴期間，待在機庫裡會更安全一些。"},"stage":{"bg":"BASEMENT","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"익숙한 일이지.","JPN":"それには慣れているな。","ENG":"It's what I'm used to.","TWN":"早就習慣了。"},"stage":{"bg":"BASEMENT","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그건 그렇고, 오늘 면접을 보셨다던 직원 말입니다만…","JPN":"ところで、今日面接をした人なんですが……","ENG":"Other than that, about the employee who came in for an interview today...","TWN":"對了，關於你今天面試的那位員工……"},"stage":{"bg":"BASEMENT","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사라진 그로니아 영웅을 관리국 태스크포스가 데리고 있단 사실이 밝혀지면 국제적인 문제로 번질 수 있습니다.","JPN":"管理局のタスクフォースに消えたグロニアの英雄が所属している、という事実が表沙汰になったら、国際的な騒ぎになりかねません。","ENG":"If people find out that an Administration TASKFORCE has employed the disappeared hero of Gronia, it could lead to some international disputes.","TWN":"萬一外人知道消失的格羅尼亞英雄在管理局特遣勢力，這有可能會演變成國際糾紛。"},"stage":{"bg":"BASEMENT","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"걱정 말게. 크리스 양은 비공식 소대로 활동하게 될 테니까.","JPN":"心配するな。クリス君は非公式小隊として活動することになるから。","ENG":"Don't worry. Chris will only be a part of our unofficial squad.","TWN":"別擔心，克莉絲會作為非正式小隊活動。"},"stage":{"bg":"BASEMENT","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"적어도, 이곳에서 벌어진 문제가 해결될 때까지는 그렇게 해야겠지.","JPN":"少なくとも、ここで起こった問題が解決される前まではな。","ENG":"At least until the problem here gets resolved.","TWN":"至少會持續到這裡的問題解決為止。"},"stage":{"bg":"BASEMENT","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"로터스 측에선 아무런 소식이 없던가요?","JPN":"ロータス側からは何も連絡がなかったのですか？","ENG":"Any news from Lotus?","TWN":"洛德斯那邊沒任何消息嗎？"},"stage":{"bg":"BASEMENT","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 난리가 있었으니 한 번쯤 낯짝을 내밀 법도 한데 말이죠.","JPN":"あんな騒ぎがあったのだから、一度くらいは顔を出してもおかしくないのですが。","ENG":"After all that mess, it's weird she hasn't shown up yet.","TWN":"經過這麼一番折騰，他們應該差不多露一下面了吧。"},"stage":{"bg":"BASEMENT","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇지 않아도 한 번 찾아가서 얘길 나눠보려던 참이네.","JPN":"そうしなくても、こちらから出向いて話し合おうと思っていたところだ。","ENG":"I'm actually planning on going over there to have a talk.","TWN":"我正打算去找他們聊聊。"},"stage":{"bg":"SKY","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이쪽 시니어는 나와 비슷한 과라 그런지. 누가 찾지 않으면 하루 종일 방구석에 박혀 있거든.","JPN":"こっちのシニアは私と似ているのか。誰かが訪ねなければ一日中部屋に閉じこもっているようでな。","ENG":"The Senior over there and I are similar. If someone doesn't come to us, we'll be stuck in our rooms all day.","TWN":"這位Senior和我一樣，要是沒人找就會一整天待在屋裡不動。"},"stage":{"bg":"SKY","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"타기리온에게 한 방 먹었으니, 그 복수심 넘치는 여자도 벼르고 있겠죠.","JPN":"タギリオンに一発お見舞いしてやったから、あの復讐心溢れる女も待ち構えているでしょう。","ENG":"That vengeful woman must be itching for retribution after what Thagirion did to her.","TWN":"既然挨了塔基里翁一記，那個女人也一定在尋找復仇的機會。"},"stage":{"bg":"SKY","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아무쪼록 협상이 원만하게 이뤄지길 바랍니다.","JPN":"どうか交渉がスムーズに終わるといいですね。","ENG":"Anyway, I hope you and her come to an agreement.","TWN":"希望談判順利。"},"stage":{"bg":"SKY","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 준비가 되면 조만간 다시 연락하지.","JPN":"ああ。準備が整ったら、そのうちまた連絡しよう。","ENG":"Yeah. I'll call you back once everything is ready.","TWN":"好的。等我準備好再聯絡你。"},"stage":{"bg":"SKY","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};